/**@ch 開始Spin，處理相關設置 */
StartSpin()
{
    // 關鍵：每次 Spin 都必須重置時間相關狀態，否則第二次會沿用上一局 StopTime/m_time 導致直接停輪
    this.m_time = 0;
    this.StopTime = 0;
    this.m_isStop = false;
    // 修 R-1：StartSpin 即凍結轉輪（恢復舊版首幀凍結），使 StartSpin→TriggerDropOut 窗口舊盤面靜止，
    // 預告蓋在靜止舊盤上；drop-in 原子解除才設回 false。
    this.m_isInDropMode = true;
    // 清掉上一局可能殘留的動畫 handle（如 MgOmen 未消費），確保本局 TriggerDropOut 冪等鍵以 null 起點、
    // 能正常建立本局的掉落動畫（INV-3 兜底，防 stale promise 污染下一局）。
    this.m_dropAllSymbolsOutOfScreenPromise = null;
    this.m_isClickStopBtn = false;
    this.m_isPlayStopSound = [ false, false, false, false, false, false ];
    this.m_isPlayStopEffect = [ false, false, false, false, false, false ];
    this.m_isHasScatterNearWin = false;

    // 強制關閉上一局殘留的 NearWin 特效
    if (this.m_scatterNearWinColumn > -1) {
        this.m_scatterNearWinColumn = -1;
        this.StopNearWinSound();
        this.SetSymbolDark(false, -1);
    }
    this.m_gameView.EffectPlate.StopNearWin();

    // 恢復上一局隱藏的 Scatter symbol
    for (const pos of this.m_hiddenScatterPositions) {
        this.SetSymbolShow(pos.col, pos.row, true);
    }
    this.m_hiddenScatterPositions = [];
    this.m_gameView.EffectPlate.ReturnAllScatterEnterAnimationNodes();

    // 防禦性清除：確保所有 symbol 的 sprite 子節點是 active 的 + 移除殘留 reparented 節點
    for (let col = 0; col < Game_Define.COL; col++) {
        const vc = this.GetVisibleSymbolCount(col);
        for (let row = 0; row < vc; row++) {
            const cell = this.GetSymbolSingleCellFromColRow(col, row);
            if (!cell) continue;
            const children = cell.ThisNode.children;
            for (let i = children.length - 1; i >= 0; i--) {
                const child = children[i];
                if (child['_reparented']) {
                    child.removeFromParent();
                    child.active = false;
                    delete child['_reparented'];
                    delete child['_origParent'];
                }
            }
            if (children[0]) children[0].active = true;
        }
    }

    // 恢復所有符號的圖層順序
    this.ResetAllSymbolLayers();

    // 重要：重置每輪的停輪時間，等待 server 回來再由 SetReelTimes() 設定
    for ( let i = 0; i < Game_Define.COL; ++i )
    {
        this.m_reelStopTime[ i ] = this.m_reelPreTime[ i ] = null;
        this.m_nearWinSpeedUp[ i ] = 1;
    }

    // 重置所有符號切換狀態（但保留鎖定狀態）
    for ( let col = 0; col < this.m_isChangeToFinalSymbol.length; ++col )
    {
        // 只重置未鎖定的轉輪
        if ( !this.m_lockColumn[ col ] )
        {
            this.m_isChangeToFinalSymbol[ col ] = false;
        }
    }

    // 清空並重新初始化有效的列索引（只對中輪帶）
    this.m_isNotChangeSymbolThisRound = {};
    for ( let col = 0; col < Game_Define.COL; ++col )
    {
        this.m_isNotChangeSymbolThisRound[ col ] = true;
    }

    // 初始化上下輪帶狀態
    this.m_upDownReelChangeState = {};
    for ( let plate = 0; plate < SHOW_COLUMNS; ++plate )
    {
        for ( let col = 0; col < Game_Define.COL; ++col )
        {
            const nodeName = Game_Define.NODE_PREFIX_NAME[ plate ] + col.toString();
            if ( plate !== Game_Define.MIDDLE_PLATE_INDEX ) // 只處理上下輪帶
            {
                this.m_upDownReelChangeState[ nodeName ] = true;
            }
        }
    }

    // 設定假轉輪帶隨機行數位置

    // 掉落模式：舊盤面掉出畫面的「實際觸發」已移出 StartSpin，改由各 path-aware 點在
    // ShowBigAwardHint（大獎預告）結束後呼叫 TriggerDropOut()（一般遊戲=OnRecvSpinAck、FG=SpinState）。
}

/**
 * @ch 觸發「舊盤面掉出畫面」（path-aware 觸發點，須在 ShowBigAwardHint 之後、drop-in 的 await 之前呼叫）
 * @description INV-1：同步成對設定凍結旗標 + 建立動畫 promise，無中間 await。
 *              INV-4：對「已在 drop mode」為 no-op（冪等），防止同一局重複觸發建立孤兒 promise。
 */
public TriggerDropOut(): void {
    // INV-4 冪等：冪等鍵改判「動畫 handle 是否已建立」（非凍結旗標 m_isInDropMode）。
    // 因 m_isInDropMode 自 StartSpin 起即為 true（凍結），不能再當冪等鍵，否則 promise 永不建立（FP-1）。
    if (this.m_dropAllSymbolsOutOfScreenPromise) {
        return;
    }
    // INV-1 設定綁定：確保凍結中（StartSpin 已設 true，此處冪等再確認）並建立掉落動畫 handle。
    this.m_isInDropMode = true;
    this.m_dropAllSymbolsOutOfScreenPromise = this.DropAllSymbolsOutOfScreen();
}

