 * @ch 將 StartFallSymbol 封裝成「依照 server 盤面資料掉落」
 * @param delayTime 延遲時間
 * @param col 列索引
 * @param row 行索引
 * @param count 落下高度（格數）
 * @param moveDuration 移動時長(秒)
 */
private async StartFallSymbolByServerPlateInfo(
    delayTime: number,
    col: number,
    row: number,
    count: number,
    moveDuration: number = Game_Define.SYMBOL_FALL_DURATION
): Promise<void> {
    const symbolId = this.GetSymbolIdFromServerPlateInfo(col, row);
    if (symbolId === null) {
        warn(`[SlotReel.StartFallSymbolByServerPlateInfo] Invalid server symbol at [col:${col}, row:${row}]`);
        return;
    }

    await this.StartFallSymbol(delayTime, col, row, count, symbolId, moveDuration);
}

/**
 * @ch 依照 server 帶來的盤面資料，讓整個可視盤面從上方掉落到盤面上
 * @param delayTime 起始延遲時間
 */
private async StartFallAllVisibleSymbolsByServerPlateInfo(delayTime: number = 0): Promise<void> {
    let nearWinExtraDelay = 0;
    const allPromises: Promise<void>[] = [];
    // 每次天降盤面都完整重新計算 scatter，避免跨 cascade 重複累計
    this.m_scatterCollectCount = 0;
    log(`[NearWin DEBUG] StartFallAll entry: m_scatterCollectCount=${this.m_scatterCollectCount}, isHasNearWin=${this.m_isHasScatterNearWin}, IsFG=${this.m_gameView.IsFreeGame}`);

    for (let col = 0; col < Game_Define.COL; col++) {
        const visibleSymbolCount = this.GetVisibleSymbolCount(col);

        if (this.m_isHasScatterNearWin) {
            // NearWin 觸發後逐顆掉入（底部先到），Scatter 落地馬上播 Stop
            for (let row = visibleSymbolCount - 1; row >= 0; row--) {
                if (this.m_isHasScatterNearWin) {
                    await this.StartFallSymbolByServerPlateInfo(0, col, row, visibleSymbolCount);
                } else {
                    // NearWin 已關閉，剩餘 symbol 並行掉落
                    allPromises.push(this.StartFallSymbolByServerPlateInfo(0, col, row, visibleSymbolCount));
                    continue;
                }
                // Scatter 落地馬上播 Stop + Enter
                const symbolId = this.GetSymbolIdFromServerPlateInfo(col, row);
                if (symbolId === Game_Define.Symbol.Scatter || symbolId === Game_Define.Symbol.SilverScatter || symbolId === Game_Define.Symbol.GoldScatter) {
                    this.m_scatterCollectCount++;
                    log(`[NearWin DEBUG] StartFallAll NearWin-active col=${col} row=${row}: count=${this.m_scatterCollectCount}`);
                    this.m_gameView.EffectPlate.ReelStopEffect(col, row, symbolId, null);
                    await this.PlayScatterAnimation(col, row, false);
                    // 第 5 顆即時關閉 NearWin
                    if (this.m_scatterCollectCount >= SCATTER_NEARWIN_MAX_COUNT) {
                        this.m_isHasScatterNearWin = false;
                        this.StopNearWinSound();
                        this.m_gameView.EffectPlate.StopNearWin();
                    } else {
                        this.m_gameView.EffectPlate.PlayScatterEnterAnimation(col, row, true);
                    }
                }
                // [TargetDiag] NearWin 分支：Target/GoldTarget 落地時「沒有」建立 spine／播 Stop(IN) —— 疑似缺口
                if (symbolId === Game_Define.Symbol.Target || symbolId === Game_Define.Symbol.GoldTarget) {
                    log(`[TargetDiag] NearWin分支 target落地『未播IN』 col=${col} row=${row} symbol=${symbolId}(${symbolId === Game_Define.Symbol.GoldTarget ? 'Gold' : 'Normal'})`);
                }
            }

            if (this.HasScatterInColumn(col) && this.m_isHasScatterNearWin) {
                const idx = Math.min(this.m_scatterCollectCount - 1, SCATTER_NEARWIN_SPIN_TABLE.length - 1);
                nearWinExtraDelay += SCATTER_NEARWIN_SPIN_TABLE[idx] * 0.1;
                // 第 5 顆即時關閉 NearWin
                if (this.m_scatterCollectCount >= SCATTER_NEARWIN_MAX_COUNT) {
                    this.m_isHasScatterNearWin = false;
                    this.StopNearWinSound();
                    this.m_gameView.EffectPlate.StopNearWin();
                    nearWinExtraDelay = 0;
                }
            }

            this.m_gameView.EffectPlate.StopNearWinAt(col);

            if (this.m_isHasScatterNearWin && col < Game_Define.COL - 1) {
                this.ShowScatterPreWinAnimation(col + 1);
            }
        } else {
            // 還沒觸發 NearWin 或 NearWin 已關閉，所有列同時掉
            const colPromises: Promise<void>[] = [];
            const colDelay = this.m_gameView.IsHardStop ? 0 : SYMBOL_FALL_EFFECT_COLUMN_DELAY_TIME * col;
            for (let row = 0; row < visibleSymbolCount; row++) {
                const fallDelayTime =
                    delayTime
                    + colDelay
                    + SYMBOL_FALL_EFFECT_ROW_DELAY_TIME * (visibleSymbolCount - 1 - row);

                const fallCount = visibleSymbolCount;
                colPromises.push(this.StartFallSymbolByServerPlateInfo(fallDelayTime, col, row, fallCount));
            }

